DriverTripDetailData? _buildDriverTripDetailFromRecentStub({
  required String routeId,
  String? tripId,
}) {
  final user = _authCredentialGateway.currentUser;
  if (user == null || user.isAnonymous) {
    return null;
  }
  final stub =
      _readRecentDriverCreatedRouteById(uid: user.uid, routeId: routeId);
  if (stub == null) {
    return null;
  }
  return DriverTripDetailData(
    routeId: stub.routeId,
    routeName: stub.routeName,
    startAddress: stub.startAddress,
    endAddress: stub.endAddress,
    startPoint: DriverTripGeoPoint(lat: stub.startLat, lng: stub.startLng),
    endPoint: DriverTripGeoPoint(lat: stub.endLat, lng: stub.endLng),
    status: DriverTripCardStatus.planned,
    stops: const <DriverTripDetailStopItem>[],
    passengers: const <DriverTripDetailPassengerItem>[],
    tripId: tripId,
    srvCode: _nullableParam(stub.srvCode),
    scheduledTimeLabel: _nullableParam(stub.scheduledTime),
    routePolylineEncoded: null,
  );
}
